    for (int i = 0; i < len; i++) {
        printf("%02x ", bytes[i]);
    }
    printf("\n");
}

int main() {
    // Original string: " cmd.exe "
    uint8_t original[] = {0x20, 0x63, 0x6d, 0x64, 0x2e, 0x65, 0x78, 0x65, 0x20};

    // Wide encoded: " \x00c\x00m\x00d\x00.\x00e\x00x\x00e\x00 \x00"
    uint8_t wide[] = {0x20, 0x00, 0x63, 0x00, 0x6d, 0x00, 0x64, 0x00, 0x2e, 0x00, 0x65, 0x00, 0x78, 0x00, 0x65, 0x00, 0x20, 0x00};

    printf("Original: ");
    print_bytes(original, sizeof(original));

    printf("Wide: ");
    print_bytes(wide, sizeof(wide));

    // The issue is that when case combinations are applied to the wide string,
    // the function looks for 'a'-'z' or 'A'-'Z' characters.
    // In the wide string, 'c' is at index 2, 'm' is at index 4, etc.
    // But the case combinations function will try to swap case at those indices,
    // which will create invalid wide strings.

    // For example, if we swap 'c' to 'C' at index 2, we get:
    // 0x20, 0x00, 0x43, 0x00, 0x6d, 0x00, ...
    // This is correct.

    // But the problem is that the case combinations function doesn't know about
    // the wide encoding, so it might create atoms that don't match properly.

    return 0;
}
